send-request.set-body:
@{
        var payload = (string)context.Variables["citizenPayload"];
        var systemPrompt = @"You are the UDCSP Eligibility Pre-assessment (AI Act high-risk, Annex III §5(a)). You produce ADVISORY pre-assessments — never decisions — for residency, tax-residency or child-benefit eligibility across Denmark, Sweden and Norway. A caseworker reviews every output.

Apply deterministic rule packs in order, before any LLM reasoning:
- 🇩🇰 CPR cannot be issued before physical arrival — if arrivalDate > today set recommendation=not-yet-eligible (rule DK-CPR-arrival).
- 🇸🇪 Folkbokföring requires intended stay >= 12 months — if intendedStayMonths < 12 set not-eligible (rule SE-folkbokforing-1y).
- 🇳🇴 Folkeregisteret requires stay > 6 months; non-Nordic non-EEA need a UDI permit first.
- 🇩🇰 Udbetaling Danmark child-benefit — EU/EEA cross-border path requires consent + employment contract + birth certificates.
- 🇸🇪 Försäkringskassan barnbidrag — automatic if folkbokförd; cross-border requires Form FK 5210 + contract + birth certificates.
- 🇳🇴 NAV barnetrygd — automatic for residents; EU/EEA cross-border path requires Form NAV 33-00.07 + contract + birth certificates.
- Tax-residency: 🇩🇰 SKAT 02.050; 🇸🇪 Skatteverket Hemvistintyg or SKV 2734; 🇳🇴 Altinn RF-1306 (>183d/12m OR >270d/36m).

Rules:
- Return JSON ONLY conforming to the schema below — no prose, no markdown.
- Always set humanReviewRequired=true.
- If confidence < 0.6 OR any deterministic rule mismatches set recommendation=escalate.
- Cite evidenceIds for every rule that depends on a document.
- Never invent citizen records, policies or legal outcomes.
- citizenNotice in the citizen's locale; caseworkerSummary always in English (2-4 sentences).

Output schema (strict):
{
  ""recommendation"": ""eligible|not-eligible|not-yet-eligible|insufficient-data|escalate"",
  ""confidence"": 0.0,
  ""ruleResults"": [{""rule"":""DK-CPR-arrival"",""passed"":true,""evidenceIds"":[],""details"":""...""}],
  ""missingEvidence"": [""arrivalDate"",""employmentContract""],
  ""humanReviewRequired"": true,
  ""citizenNotice"": ""…"",
  ""caseworkerSummary"": ""…"",
  ""lineage"": {""ruleVersion"":""v1"",""promptVersion"":""v1"",""datasetVersion"":""inline""}
}";
        var body = new JObject();
        body["max_completion_tokens"] = 3500;
        body["response_format"] = new JObject(new JProperty("type","json_object"));
        var msgs = new JArray();
        msgs.Add(new JObject(
          new JProperty("role","system"),
          new JProperty("content", systemPrompt)
        ));
        msgs.Add(new JObject(
          new JProperty("role","user"),
          new JProperty("content","Citizen pre-assessment request (JSON):\n" + payload + "\n\nReturn the structured JSON per the output schema.")
        ));
        body["messages"] = msgs;
        return body.ToString();
      }

return-response.set-body:
@{
        var r = (IResponse)context.Variables["aoaiResponse"];
        if (r == null) {
          return new JObject(
            new JProperty("recommendation","escalate"),
            new JProperty("confidence", 0),
            new JProperty("humanReviewRequired", true),
            new JProperty("citizenNotice","The AI pre-assessment is temporarily unavailable. A caseworker will review your case manually."),
            new JProperty("caseworkerSummary","No response object from AOAI send-request."),
            new JProperty("error","aoai null response")
          ).ToString();
        }
        if (r.StatusCode != 200) {
          string aoaiErr = r.Body.As<string>(preserveContent: true);
          if (aoaiErr == null) { aoaiErr = ""; }
          if (aoaiErr.Length > 400) { aoaiErr = aoaiErr.Substring(0, 400); }
          return new JObject(
            new JProperty("recommendation","escalate"),
            new JProperty("confidence", 0),
            new JProperty("humanReviewRequired", true),
            new JProperty("citizenNotice","The AI pre-assessment is temporarily unavailable. A caseworker will review your case manually."),
            new JProperty("caseworkerSummary","Foundry eligibility agent returned status " + r.StatusCode + "."),
            new JProperty("error","aoai status " + r.StatusCode + ": " + aoaiErr)
          ).ToString();
        }
        JObject json = r.Body.As<JObject>(preserveContent: false);
        string content = null;
        if (json != null) {
          var choices = json["choices"] as JArray;
          if (choices != null && choices.Count > 0) {
            content = choices[0]["message"]?["content"]?.ToString();
          }
        }
        if (string.IsNullOrEmpty(content)) {
          return new JObject(
            new JProperty("recommendation","escalate"),
            new JProperty("confidence", 0),
            new JProperty("humanReviewRequired", true),
            new JProperty("citizenNotice","No content from the AI agent. A caseworker will review."),
            new JProperty("caseworkerSummary","Empty model response."),
            new JProperty("error","empty content")
          ).ToString();
        }
        return content;
      }
